// ============================================================================
// ProjectOps360° — Product Intelligence content generator (build step)
// ============================================================================
// Reads docs/product-brain/**/*.md (the single source of truth) and emits a
// bundled TypeScript module the app can import directly. This guarantees the
// Product Intelligence Center has its content at runtime on Vercel WITHOUT
// relying on filesystem tracing of files outside src/. Run automatically via
// the `prebuild` npm script; the generated file is also committed so local dev
// works without a manual step.
//
// This is NOT manual duplication: the content is derived from docs/product-brain
// on every build. GitHub remains the source of truth for version control.
// ============================================================================

import { promises as fs } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.join(__dirname, "..", "docs", "product-brain");
const OUT = path.join(__dirname, "..", "src", "lib", "product-brain", "content.generated.ts");

async function walk(dir) {
  const out = [];
  let entries;
  try {
    entries = await fs.readdir(dir, { withFileTypes: true });
  } catch {
    return out;
  }
  for (const e of entries) {
    const abs = path.join(dir, e.name);
    if (e.isDirectory()) out.push(...(await walk(abs)));
    else if (e.isFile() && e.name.toLowerCase().endsWith(".md")) out.push(abs);
  }
  return out;
}

const files = (await walk(ROOT)).sort();
const docs = [];
for (const abs of files) {
  const relPath = path.relative(ROOT, abs).split(path.sep).join("/");
  const content = await fs.readFile(abs, "utf8");
  docs.push({ relPath, content });
}

const header = `// AUTO-GENERATED by scripts/generate-product-brain-content.mjs — DO NOT EDIT.
// Source of truth: docs/product-brain/. Regenerated on every build (prebuild).

export interface RawProductBrainDoc {
  relPath: string;
  content: string;
}

export const RAW_PRODUCT_BRAIN_DOCS: RawProductBrainDoc[] = ${JSON.stringify(docs, null, 2)};
`;

await fs.mkdir(path.dirname(OUT), { recursive: true });
await fs.writeFile(OUT, header, "utf8");
console.log(`[product-brain] generated ${docs.length} docs → ${path.relative(path.join(__dirname, ".."), OUT)}`);
